import { Box, HStack, IconButton, Image, Menu, MenuButton, Text, MenuList, MenuItem } from '@chakra-ui/react';
import React, { useEffect, useState } from 'react';
import { HamburgerIcon } from "@chakra-ui/icons"
import Loading from '../Components/Loading';

const HomePage = () => {

    const [loading, setLoading] = useState(true)

    const [title, setTitle] = useState("")

    const width = "20px"

    useEffect(() => {
        document.title = title;

        setTimeout(() => {
            setLoading(false)
            setTitle("Home-Page | Juber Shaikh")
        }, 3000);
    }, [title])

    if (loading) {
        return <Loading />
    }

    return (
        <>
            <HStack spacing="0px">
                <Box w='65%' h='40rem' bg="#4831d4">
                    <Text margin="20px" color="white" fontSize="50px">Juber</Text>
                </Box>
                <Box w='35%' h='40rem' bg="#ccf381">
                    <Box margin="20px">
                        <Menu>
                            <MenuButton
                                as={IconButton}
                                icon={<HamburgerIcon />}
                                variant="outline"
                            />
                            <MenuList>
                                <MenuItem>
                                    Home
                                </MenuItem>
                                <MenuItem>
                                    My Work
                                </MenuItem>
                                <MenuItem>
                                    My Resume
                                </MenuItem>
                                <Text margin="20px" color="black" fontSize="1rem">Contact Me</Text>
                                <HStack spacing="40px">
                                    <Image width={width} src='https://cdn-icons-png.flaticon.com/512/174/174857.png' />
                                    <Image width={width} src='https://upload.wikimedia.org/wikipedia/commons/thumb/7/7e/Gmail_icon_%282020%29.svg/2560px-Gmail_icon_%282020%29.svg.png' />
                                    <Image width={width} src='https://cdn-icons-png.flaticon.com/512/25/25231.png' />
                                </HStack>
                            </MenuList>
                        </Menu>
                    </Box>
                    <Box paddingTop="20%" width="50%" marginLeft="20px">
                        <Image width="100%" src='https://bit.ly/dan-abramov' />
                    </Box>
                </Box>
            </HStack>
        </>
    );
};

export default HomePage;