import React from 'react';
import Lottie from "lottie-react"
import pagenotfound from "../asset/103035-404-not-found.json"
import { Center } from '@chakra-ui/react';

const PageNotFound = () => {

    const style={
        height:300
    }

    return (
        <Center>
            <Lottie animationData={pagenotfound} loop={true} style={style}/>
        </Center>
    );
};

export default PageNotFound;